import{_ as a,c as s,o as l,ah as e}from"./chunks/framework.Cnj7lwEt.js";const g=JSON.parse('{"title":"项目名称","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/开发工具/sub2api-开发工具.md","filePath":"github汇总/开发工具/sub2api-开发工具.md"}'),r={name:"github汇总/开发工具/sub2api-开发工具.md"};function t(h,i,n,o,d,p){return l(),s("div",null,i[0]||(i[0]=[e('<h1 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h1><p>Sub2API</p><h1 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h1><p>Wei-Shaw</p><h1 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h1><p>开发工具</p><h1 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h1><p>AI产品订阅的API配额难以安全地分享给多个用户，缺乏细粒度的管理和计费功能</p><h1 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h1><ul><li>AI API网关平台</li><li>分发和管理AI产品订阅的API配额</li><li>多账号管理（OAuth、API Key）</li><li>API Key分发和管理</li><li>Token级使用追踪和成本计算</li><li>智能调度和会话粘性</li><li>并发控制和速率限制</li><li>管理后台</li><li>支持Docker一键部署</li></ul><h1 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h1><ul><li>无需直接分享上游API密钥</li><li>细粒度的访问控制</li><li>Token级精确计费</li><li>智能调度和负载均衡</li><li>部署简单，支持多种方式</li><li>Web管理界面</li></ul><h1 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h1><p>README/仓库信息中未明确说明</p><h1 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h1><p><a href="https://github.com/Wei-Shaw/sub2api" target="_blank" rel="noreferrer">https://github.com/Wei-Shaw/sub2api</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h1 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h1><h2 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h2><p>适用于有Docker或Linux使用经验的用户</p><h2 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h2><ol><li><p><strong>Docker检查（Docker方式）</strong></p><ul><li>步骤目标：确认已安装Docker和Docker Compose</li><li>执行位置：本机终端</li><li>完整命令：<code>docker --version</code> 和 <code>docker-compose --version</code></li><li>成功标志：显示Docker和Docker Compose版本号</li><li>失败处理：访问 <a href="https://www.docker.com/" target="_blank" rel="noreferrer">Docker官网</a> 安装</li></ul></li><li><p><strong>系统要求（脚本方式）</strong></p><ul><li>步骤目标：确认Linux系统环境</li><li>执行位置：本机终端</li><li>操作说明：需要Linux服务器（amd64或arm64）、PostgreSQL 15+、Redis 7+、Root权限</li><li>成功标志：环境满足要求</li><li>失败处理：准备符合要求的服务器环境</li></ul></li></ol><h2 id="主路径-docker-compose部署-推荐" tabindex="-1">主路径：Docker Compose部署（推荐） <a class="header-anchor" href="#主路径-docker-compose部署-推荐" aria-label="Permalink to “主路径：Docker Compose部署（推荐）”">​</a></h2><h3 id="步骤1-创建部署目录" tabindex="-1">步骤1：创建部署目录 <a class="header-anchor" href="#步骤1-创建部署目录" aria-label="Permalink to “步骤1：创建部署目录”">​</a></h3><ul><li><strong>步骤目标</strong>：创建部署目录</li><li><strong>执行位置</strong>：本机终端</li><li><strong>完整命令</strong>：<div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sub2api-deploy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sub2api-deploy</span></span></code></pre></div></li><li><strong>成功标志</strong>：目录创建成功</li><li><strong>失败处理</strong>：检查目录权限</li></ul><h3 id="步骤2-下载部署脚本" tabindex="-1">步骤2：下载部署脚本 <a class="header-anchor" href="#步骤2-下载部署脚本" aria-label="Permalink to “步骤2：下载部署脚本”">​</a></h3><ul><li><strong>步骤目标</strong>：下载并运行部署准备脚本</li><li><strong>执行位置</strong>：部署目录</li><li><strong>完整命令</strong>：<div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/Wei-Shaw/sub2api/main/deploy/docker-deploy.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div></li><li><strong>成功标志</strong>：脚本执行完成</li><li><strong>失败处理</strong>：检查网络连接</li></ul><h3 id="步骤3-启动服务" tabindex="-1">步骤3：启动服务 <a class="header-anchor" href="#步骤3-启动服务" aria-label="Permalink to “步骤3：启动服务”">​</a></h3><ul><li><strong>步骤目标</strong>：启动Docker Compose服务</li><li><strong>执行位置</strong>：部署目录</li><li><strong>完整命令</strong>：<div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker-compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span></span></code></pre></div></li><li><strong>成功标志</strong>：服务启动成功</li><li><strong>失败处理</strong>：查看Docker日志排查错误</li></ul><h2 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h2><ul><li><strong>访问地址</strong>：http://YOUR_SERVER_IP:8080</li><li><strong>预期返回</strong>：Sub2API管理界面正常显示</li></ul><h2 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h2><ol><li><p><strong>现象</strong>：服务启动失败</p><ul><li><strong>可能原因</strong>：端口被占用、配置错误</li><li><strong>解决步骤</strong>：检查端口占用，查看.env配置</li></ul></li><li><p><strong>现象</strong>：无法访问管理界面</p><ul><li><strong>可能原因</strong>：防火墙问题</li><li><strong>解决步骤</strong>：检查防火墙设置，开放8080端口</li></ul></li><li><p><strong>现象</strong>：上游API连接失败</p><ul><li><strong>可能原因</strong>：API密钥配置错误、网络问题</li><li><strong>解决步骤</strong>：检查API密钥配置，确认网络能访问上游服务</li></ul></li></ol><h2 id="备选部署路径" tabindex="-1">备选部署路径 <a class="header-anchor" href="#备选部署路径" aria-label="Permalink to “备选部署路径”">​</a></h2><h3 id="脚本安装-linux" tabindex="-1">脚本安装（Linux） <a class="header-anchor" href="#脚本安装-linux" aria-label="Permalink to “脚本安装（Linux）”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/Wei-Shaw/sub2api/main/deploy/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span></span></code></pre></div><h3 id="从源码构建" tabindex="-1">从源码构建 <a class="header-anchor" href="#从源码构建" aria-label="Permalink to “从源码构建”">​</a></h3><p>需要Go 1.21+、Node.js 18+、PostgreSQL 15+、Redis 7+</p><h2 id="官方文档与补充入口" tabindex="-1">官方文档与补充入口 <a class="header-anchor" href="#官方文档与补充入口" aria-label="Permalink to “官方文档与补充入口”">​</a></h2><p>项目地址：<a href="https://github.com/Wei-Shaw/sub2api" target="_blank" rel="noreferrer">https://github.com/Wei-Shaw/sub2api</a> <a href="/网络环境.html">海外网络环境配置 →</a></p>',39)]))}const c=a(r,[["render",t]]);export{g as __pageData,c as default};
